// ============================================================
// Build notification message.
// ============================================================

const project = $('Load Active Project').first().json;
const chapter = $('Call Writer Service').first().json.data;
const finalScore = $('Collect All Reviews').first().json.final_score;
const blogPost = $('Save Blog Post Record').first().json;
const job = $('Build Writing Brief').first().json;

return [{
  json: {
    message: `📖 **${project.title}**\n` +
      `Chapter ${$('Select Next Chapter Plan').first().json.sequence}: ${chapter.title}\n` +
      `Words: ${chapter.word_count} | Score: ${finalScore}\n` +
      `Status: ${job.auto_publish && finalScore >= job.quality_threshold ? 'Published' : 'Draft'}\n` +
      `URL: ${blogPost.url || 'N/A'}`,
    subject: `[Novel Factory] ${project.title} Ch${$('Select Next Chapter Plan').first().json.sequence} — Score ${finalScore}`,
    project_title: project.title,
    chapter_title: chapter.title,
    word_count: chapter.word_count,
    score: finalScore,
    url: blogPost.url || '',
    needs_human_review: false
  }
}];

// ============================================================
// Global error handler — catches workflow failures.
// Records to generation_jobs.
// ============================================================

const error = $input.first().json;

return [{
  json: {
    error: error.message || 'Unknown workflow error',
    node: error.node || 'unknown',
    timestamp: new Date().toISOString(),
    job_id: $('Build Writing Brief').first()?.json?.job_id || null
  }
}];
